import { useState } from "react";

export default function NestedList() {
  const [data, setData] = useState([
    {
      type: "root",
      title: "Главный список",
      titleInput: "",
      fields: [
        { id: 1, value: "" },
        { id: 2, value: "" }
      ],
      children: []
    }
  ]);

  // --- Функции обновления состояния ---

  function getNode(copy, path) {
    let node = copy;
    for (let index of path) {
      node = node[index];
    }
    return node;
  }

  function updateTitle(path, value) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);

      if (node.type === "root") node.title = value;
      else node.titleInput = value;

      return copy;
    });
  }

  function updateField(path, fieldIndex, value) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);
      node.fields[fieldIndex].value = value;
      return copy;
    });
  }

  function addField(path) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);
      node.fields.push({
        id: Date.now(),
        value: ""
      });
      return copy;
    });
  }

  function addChildList(path) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);

      node.children.push({
        type: "child",
        title: "",
        titleInput: "",
        fields: [],
        children: []
      });

      return copy;
    });
  }

  // --- Рекурсивный компонент отрисовки списка ---

  function RenderList({ node, path }) {
    return (
      <div style={{ marginLeft: 20 }}>
        
        {node.type === "root" ? (
          <h2
            contentEditable
            suppressContentEditableWarning
            onBlur={(e) => updateTitle(path, e.target.innerText)}
          >
            {node.title}
          </h2>
        ) : (
          <input
            placeholder="Название списка"
            value={node.titleInput}
            onChange={(e) => updateTitle(path, e.target.value)}
          />
        )}

        {/* Поля */}
        {node.fields.map((f, i) => (
          <input
            key={f.id}
            placeholder="Поле"
            value={f.value}
            onChange={(e) => updateField(path, i, e.target.value)}
          />
        ))}

        <button onClick={() => addField(path)}>
          Добавить поле
        </button>

        {/* Вложенные списки */}
        {node.children.map((child, i) => (
          <RenderList
            key={i}
            node={child}
            path={[...path, "children", i]}
          />
        ))}

        <button onClick={() => addChildList(path)}>
          Добавить вложенный список
        </button>
      </div>
    );
  }

  // --- Основной рендер ---
  return (
    <div>
      {data.map((item, i) => (
        <RenderList key={i} node={item} path={[i]} />
      ))}
    </div>
  );
}
